    10→type SqrcUserTopicProgressRepository struct {
    11→	sqrc db.Querier
    12→}
    13→
    14→func NewSqrcUserTopicProgressRepository(q db.Querier) *SqrcUserTopicProgressRepository {
    15→	return &SqrcUserTopicProgressRepository{sqrc: q}
    16→}
    17→
    18→func (repository *SqrcUserTopicProgressRepository) getProgress(ctx context.Context, userId string, courseId string) (Progress, error) {
    19→	var userIdUuid, courseIdUuid pgtype.UUID
    20→
    21→	if err := userIdUuid.Scan(userId); err != nil {
    22→		return Progress{}, err
    23→	}
    24→	if err := courseIdUuid.Scan(courseId); err != nil {
    25→		return Progress{}, err
    26→	}
    27→
    28→	rows, err := repository.sqrc.GetProgressByUserIdAndCourseId(ctx, db.GetProgressByUserIdAndCourseIdParams{
    29→		Userid:   userIdUuid,
    30→		Courseid: courseIdUuid,
    31→	})
    32→	if err != nil {
    33→		return Progress{}, err
    34→	}
    35→
    36→	records := make([]ProgressRecord, len(rows))
    37→	for i, row := range rows {
    38→		records[i] = ProgressRecord{
    39→			courseSectionTopicId: row.CourseSectionTopicID.String(),
    40→			sectionNumber:        int(row.SectionIndex),
    41→			topicNumber:          int(row.TopicIndex),
    42→			status:               row.Status,
    43→		}
    44→	}
    45→
    46→	return Progress{courseId: courseId, userId: userId, records: records}, nil
    47→}
    48→
    49→func (repository *SqrcUserTopicProgressRepository) save(ctx context.Context, progress *Progress) error {
    50→	for _, record := range progress.records {
    51→		var topicIdUuid, userIdUuid pgtype.UUID
    52→		if err := topicIdUuid.Scan(record.courseSectionTopicId); err != nil {
    53→			return err
    54→		}
    55→		if err := userIdUuid.Scan(progress.userId); err != nil {
    56→			return err
    57→		}
    58→
    59→		if err := repository.sqrc.UpsertProgress(ctx, db.UpsertProgressParams{
    60→			Coursesectiontopicid: topicIdUuid,
    61→			Userid:               userIdUuid,
    62→			Status:               record.status,
    63→		}); err != nil {
    64→			return err
    65→		}
    66→	}
    67→	return nil
    68→}
