     7→)
     8→
     9→type EnrollCourseUsecaseParams struct {
    10→	userId        string
    11→	courseId      string
    12→	sectionNumber *int
    13→	topicNumber   *int
    14→}
    15→
    16→type EnrollCourseUsecase struct {
    17→	courseRepository   CourseRepository
    18→	progressRepository ProgressRepository
    19→}
    20→
    21→func NewEnrollCourseUsecase(courseRepo CourseRepository, progressRepo ProgressRepository) EnrollCourseUsecase {
    22→	return EnrollCourseUsecase{
    23→		courseRepository:   courseRepo,
    24→		progressRepository: progressRepo,
    25→	}
    26→}
    27→
    28→type CourseRepository interface {
    29→	getCourseByCourseId(ctx context.Context, courseId string) (Course, error)
    30→}
    31→
    32→type ProgressRepository interface {
    33→	getProgress(ctx context.Context, userId string, courseId string) (Progress, error)
    34→	save(ctx context.Context, progress *Progress) error
    35→}
    36→
    37→type EnrollCourseUsecaseInterface interface {
    38→	execute(ctx context.Context, params EnrollCourseUsecaseParams) (string, error)
    39→}
    40→
    41→func (usecase EnrollCourseUsecase) execute(ctx context.Context, params EnrollCourseUsecaseParams) (string, error) {
    42→	var course Course
    43→	var progress Progress
    44→
    45→	g, gctx := errgroup.WithContext(ctx)
    46→	g.Go(func() error {
    47→		var err error
    48→		course, err = usecase.courseRepository.getCourseByCourseId(gctx, params.courseId)
    49→		return err
    50→	})
    51→	g.Go(func() error {
    52→		var err error
    53→		progress, err = usecase.progressRepository.getProgress(gctx, params.userId, params.courseId)
    54→		return err
    55→	})
    56→
    57→	if err := g.Wait(); err != nil {
    58→		return "", err
    59→	}
    60→
    61→	if err := course.checkEnrollable(params.userId); err != nil {
    62→		return "", err
    63→	}
    64→
    65→	section, topic, err := course.findTopicToStart(params.sectionNumber, params.topicNumber, progress.lastTopicPosition())
    66→	if err != nil {
    67→		return "", err
    68→	}
    69→
    70→	topicId := progress.start(section, topic)
    71→
    72→	return topicId, usecase.progressRepository.save(ctx, &progress)
    73→}
