    73→func (p *Progress) lastTopicPosition() ProgressPosition {
    74→	pos := ProgressPosition{sectionNumber: -1, topicNumber: -1, status: "NOT_STARTED"}
    75→
    76→	for _, record := range p.records {
    77→		if record.sectionNumber > pos.sectionNumber || (record.sectionNumber == pos.sectionNumber && record.topicNumber > pos.topicNumber) {
    78→			pos = ProgressPosition{sectionNumber: record.sectionNumber, topicNumber: record.topicNumber, status: record.status}
    79→		}
    80→	}
    81→
    82→	return pos
    83→}
