    85→func (p *Progress) start(section Section, topic Topic) string {
    86→	for _, record := range p.records {
    87→		if record.courseSectionTopicId == topic.topicId {
    88→			return topic.topicId
    89→		}
    90→	}
    91→
    92→	p.records = append(p.records, ProgressRecord{
    93→		courseSectionTopicId: topic.topicId,
    94→		sectionNumber:        section.number,
    95→		topicNumber:          topic.number,
    96→		status:               "IN_PROGRESS",
    97→		startedAt:            time.Now().Format(time.RFC3339),
    98→		completedAt:          nil,
    99→	})
   100→	return topic.topicId
   101→}
