   114→func (course *Course) findTopicToStart(sectionNumber *int, topicNumber *int, lastPosition ProgressPosition) (Section, Topic, error) {
   115→	if sectionNumber == nil && topicNumber != nil {
   116→		return Section{}, Topic{}, ErrTopicNumberRequireSectionNumber
   117→	}
   118→
   119→	var secNum, topNum int
   120→
   121→	if sectionNumber != nil {
   122→		secNum = *sectionNumber
   123→		if topicNumber != nil {
   124→			topNum = *topicNumber
   125→		}
   126→	} else {
   127→		switch lastPosition.status {
   128→		case "COMPLETED":
   129→			nextPosition, err := course.nextTopic(TopicPosition{sectionNumber: lastPosition.sectionNumber, topicNumber: lastPosition.topicNumber})
   130→			if err != nil {
   131→				return Section{}, Topic{}, ErrEnrollmentNumberIsNotFound
   132→			}
   133→			secNum, topNum = nextPosition.sectionNumber, nextPosition.topicNumber
   134→		case "IN_PROGRESS":
   135→			secNum = lastPosition.sectionNumber
   136→			topNum = lastPosition.topicNumber
   137→		default:
   138→			secNum = 0
   139→			topNum = 0
   140→		}
   141→	}
   142→
   143→	section, topic, err := course.getTopic(secNum, topNum)
   144→	if err != nil {
   145→		return Section{}, Topic{}, ErrEnrollmentNumberIsNotFound
   146→	}
   147→	return section, topic, nil
   148→}
