   150→type TopicPosition struct {
   151→	sectionNumber int
   152→	topicNumber   int
   153→}
   154→
   155→var ErrTopicPositionOutOfRange = errors.New("topic position is out of range")
   156→
   157→func (course *Course) getTopic(sectionNumber int, topicNumber int) (Section, Topic, error) {
   158→	if sectionNumber < 0 || sectionNumber >= len(course.sections) {
   159→		return Section{}, Topic{}, ErrTopicPositionOutOfRange
   160→	}
   161→	section := course.sections[sectionNumber]
   162→	if topicNumber < 0 || topicNumber >= len(section.topics) {
   163→		return Section{}, Topic{}, ErrTopicPositionOutOfRange
   164→	}
   165→	return section, section.topics[topicNumber], nil
   166→}
   167→
   168→func (course *Course) nextTopic(currentTopicPosition TopicPosition) (topicPosition TopicPosition, err error) {
   169→	if currentTopicPosition.sectionNumber < 0 || currentTopicPosition.sectionNumber >= len(course.sections) {
   170→		return TopicPosition{}, ErrTopicPositionOutOfRange
   171→	}
   172→
   173→	section := course.sections[currentTopicPosition.sectionNumber]
   174→	if currentTopicPosition.topicNumber < 0 || currentTopicPosition.topicNumber >= len(section.topics) {
   175→		return TopicPosition{}, ErrTopicPositionOutOfRange
   176→	}
   177→
   178→	if currentTopicPosition.topicNumber == len(section.topics)-1 {
   179→		if currentTopicPosition.sectionNumber == len(course.sections)-1 {
   180→			return TopicPosition{}, ErrTopicPositionOutOfRange
   181→		}
   182→		return TopicPosition{sectionNumber: currentTopicPosition.sectionNumber + 1, topicNumber: 0}, nil
   183→	}
   184→
   185→	return TopicPosition{sectionNumber: currentTopicPosition.sectionNumber, topicNumber: currentTopicPosition.topicNumber + 1}, nil
   186→}
